customCSS:
/* LINE 主题 */

/* 聊天背景 */
.chat-messages {
  background-color: #7494C0 !important;
}

/* 头部样式 */
.chat-header {
  background: rgba(240, 240, 240, 0.92) !important;
  backdrop-filter: blur(10px) !important;
  -webkit-backdrop-filter: blur(10px) !important;
  min-height: 100px !important;
}
.chat-header-back {
  color: #000 !important;
}
.chat-header-actions {
  color: #000 !important;
}
.chat-header-avatar {
  display: none !important;
}
.chat-header-name-text {
  font-size: 17px !important;
  font-weight: 700 !important;
}
.chat-header-name-arrow {
  display: none !important;
}

/* 禁用原有的 iMessage 底部尾巴 */
.bubble-user.has-tail::before,
.bubble-user.has-tail::after,
.bubble-ai.has-tail::before,
.bubble-ai.has-tail::after {
  display: none !important;
}
.bubble-user.has-tail {
  border-bottom-right-radius: var(--bubble-radius) !important;
}
.bubble-ai.has-tail {
  border-bottom-left-radius: var(--bubble-radius) !important;
}

/* LINE 风格顶部尾巴 - 用户(右) */
.bubble-user {
  border-top-right-radius: 4px !important;
  margin-right: 6px !important;
  position: relative !important;
}
.bubble-user::before {
  content: '' !important;
  display: block !important;
  position: absolute !important;
  top: 0 !important;
  right: -6px !important;
  width: 10px !important;
  height: 12px !important;
  background-color: var(--bubble-user-bg, #8DE055) !important;
  clip-path: path('M 0 0 L 8 0 Q 4 5 0 10 Z') !important;
}
.bubble-user::after {
  display: none !important;
}

/* LINE 风格顶部尾巴 - AI(左) */
.bubble-ai {
  border-top-left-radius: 4px !important;
  margin-left: 6px !important;
  position: relative !important;
}
.bubble-ai::before {
  content: '' !important;
  display: block !important;
  position: absolute !important;
  top: 0 !important;
  left: -6px !important;
  width: 10px !important;
  height: 12px !important;
  background-color: var(--bubble-ai-bg, #FFFFFF) !important;
  clip-path: path('M 10 0 L 2 0 Q 6 5 10 10 Z') !important;
}
.bubble-ai::after {
  display: none !important;
}

/* 时间戳样式 */
.chat-timestamp {
  background: rgba(0,0,0,0.15) !important;
  color: #fff !important;
  font-size: 11px !important;
  padding: 4px 12px !important;
  border-radius: 20px !important;
  backdrop-filter: blur(4px) !important;
}

/* 消息时间/已读 - 在蓝色背景上用深色 */
.msg-meta {
  color: #3d5a73 !important;
}

/* 旁白样式 - 在蓝色背景上更清晰 */
.narration {
  background: rgba(255,255,255,0.85) !important;
  color: #333 !important;
  backdrop-filter: blur(8px) !important;
}

/* 输入区域 */
.glass-input-area {
  background: #fff !important;
  border-top: 1px solid rgba(0,0,0,0.1) !important;
}
.chat-input-field {
  background: #F3F3F3 !important;
  border: none !important;
}
.chat-input-left {
  color: #1E2329 !important;
}
.chat-input-plus,
.chat-input-camera,
.chat-input-image {
  color: #1E2329 !important;
}
.chat-input-emoji-inside {
  color: #888 !important;
}
.chat-input-mic {
  color: #1E2329 !important;
}

/* 发送按钮 LINE 风格 */
.chat-input-send-icon {
  background: #06C755 !important;
  color: #fff !important;
}

/* 深色模式覆盖 */
.dark .chat-messages {
  background-color: #1a1a2e !important;
}
.dark .chat-header {
  background: rgba(30, 30, 30, 0.92) !important;
}
.dark .chat-header-back,
.dark .chat-header-actions,
.dark .chat-header-name-text {
  color: #fff !important;
}
.dark .msg-meta {
  color: #a0b0c0 !important;
}
.dark .narration {
  background: rgba(0,0,0,0.5) !important;
  color: #ddd !important;
}
.dark .glass-input-area {
  background: #1c1c1e !important;
}
.dark .chat-input-field {
  background: #2c2c2e !important;
}
.dark .chat-input-plus,
.dark .chat-input-camera,
.dark .chat-input-image,
.dark .chat-input-mic {
  color: #fff !important;
}
